// Twisty Fidget Ball — a sphere carved into bold spiraling petal-slices.
// Technique: build a multi-lobe 2D profile (a circle modulated into N broad
// petals with DEEP valleys between them), extrude it tall with a big twist +
// high nDiv so the lobes spiral smoothly around Z, then intersect that twisted
// column with a sphere to clip it to a ball silhouette. The deep petal valleys
// become pronounced spiraling channels; the crests become raised petal-ridges.
const { Manifold, CrossSection } = api;

const p = api.params({
  radius: { type: 'number', default: 24, min: 14, max: 40, step: 1, unit: 'mm', label: 'Ball radius' },
  petals: { type: 'int',    default: 6,  min: 4,  max: 12, label: 'Petal count' },
  twist:  { type: 'number', default: 540, min: 180, max: 720, step: 30, unit: '°', label: 'Total twist' },
});

const R = p.radius;
const lobes = p.petals;

// Petal profile: a circle whose radius swells (crest) and pinches (valley)
// `lobes` times around the perimeter. Crests sit proud of the sphere so the
// petal tops are clipped flat-round by it; valleys cut DEEP toward the center so
// the spiral channels are unmistakable from every angle.
//   crest  : 1.06·R  (just outside the sphere — petal top)
//   valley : 0.62·R  (deep groove ~0.38·R below the crest)
// A shaping exponent makes the petals broad and the valleys narrow + deep, so
// each spiral slice reads as a distinct bold ridge rather than a faint scuff.
const crestR = R * 1.06;
const groove = R * 0.44;          // crest-to-valley dip (~0.44·R) — bold channels
const sharp  = 2.2;               // >1 broadens petals & deepens/narrows valleys
const pts = [];
const N = 360;                    // perimeter samples — smooth lobes
for (let i = 0; i < N; i++) {
  const a = (i / N) * Math.PI * 2;
  // wave: 1 at crests, 0 at valleys. Raising to `sharp` keeps the crest flat-ish
  // and broad while plunging the valley to a deep, narrow channel.
  const wave = Math.pow((1 + Math.cos(lobes * a)) / 2, sharp);
  const rr = crestR - groove * (1 - wave);
  pts.push([rr * Math.cos(a), rr * Math.sin(a)]);
}
const profile = CrossSection.ofPolygons([pts]);

// Extrude taller than the sphere diameter so the clipped band is full of twist,
// centered on the origin so the sphere sits in the middle of the column.
// High nDiv (128) keeps the strong twist smooth and unfaceted.
const colH = R * 2.4;
const column = profile.extrude(colH, 128, p.twist, undefined, true);

// Clip the twisted column to a ball. The sphere inherits the user's quality
// preset for a clean round silhouette.
const ball = Manifold.sphere(R);
const twisty = column.intersect(ball);

// Vivid filament orange — punchier than the muddy '#ff7a18'.
return api.label(twisty, 'twisty-ball', { color: '#ff8124' });

